impl std :: fmt :: Display for BalanceError { fn fmt (& self , f : & mut std :: fmt :: Formatter < '_ >) -> std :: fmt :: Result { match self { BalanceError :: OwnedUnbalanced { var , dups , uses , drops , } => write ! (f , "owned binding `{var}` is RC-unbalanced: 1 + dups({dups}) != uses({uses}) + \
                 drops({drops})") , BalanceError :: BorrowedHasRcOps { var , dups , drops } => write ! (f , "borrowed binding `{var}` must carry no Dup/Drop, but has dups({dups}) + \
                 drops({drops})") , } } }

impl std :: fmt :: Display for EmitError { fn fmt (& self , f : & mut std :: fmt :: Formatter < '_ >) -> std :: fmt :: Result { match self { EmitError :: UnsupportedNode (kind) => write ! (f , "RC-emission does not yet support `{kind}` (recursion is a later MEM-4 increment — \
                 DN-33 §6); refusing rather than mis-emitting (G2)") , EmitError :: DepthExceeded { limit } => write ! (f , "RC-emission's own AST-traversal recursion exceeded the depth budget (limit \
                 {limit} frames) — refusing rather than overflowing the host stack (RFC-0041 §4.7, G2)") , } } }

impl std :: fmt :: Display for RcError { fn fmt (& self , f : & mut std :: fmt :: Formatter < '_ >) -> std :: fmt :: Result { match self { RcError :: UnboundVar (v) => write ! (f , "unbound variable `{v}`") , RcError :: UseAfterFree (v) => write ! (f , "use-after-free: `{v}` read/moved after reclaim") , RcError :: DoubleFree (v) => { write ! (f , "double free: reference count of `{v}` went negative") } RcError :: UnsoundUnique { var , found } => write ! (f , "unsound rc==1 annotation: `{var}` was marked sole-owner (MoveUnique) but its \
                 reference count was {found}, not 1") , RcError :: UnsupportedNode (k) => { write ! (f , "RC-evaluator does not support `{k}` (straight-line fragment only)") } RcError :: DepthExceeded { limit } => write ! (f , "RC-evaluator's own IR-traversal recursion exceeded the depth budget (limit \
                 {limit} frames) — refusing rather than overflowing the host stack (RFC-0041 §4.7, G2)") , } } }
